const results = [];
// Combine inputs from Follower Stats and Share Stats nodes
// n8n outputs them as separate lists or we can merge them by organization urn
const followerStats = $('Fetch Follower Stats').all();
const shareStats = $('Fetch Share Stats').all();
const pages = $('Get Active LinkedIn Pages').all();

for (const page of pages) {
  const urn = page.json.urn;
  const dbId = page.json.id;

  const fStat = followerStats.find(item => item.json.organizationalEntity === urn) || { json: {} };
  const sStat = shareStats.find(item => item.json.organizationalEntity === urn) || { json: {} };

  // LinkedIn returns statistics in nested arrays (e.g. elements[0].followerCountsByStaffCountRange, etc.)
  // We will parse out the primary follower count and aggregate shares statistics
  const totalFollowers = fStat.json.elements?.[0]?.firstDegreeFollowerResults?.followerCounts?.organicFollowerCount || 0;

  const totalImpressions = sStat.json.elements?.[0]?.totalShareStatistics?.impressionCount || 0;
  const totalShares = sStat.json.elements?.[0]?.totalShareStatistics?.shareCount || 0;
  const totalLikes = sStat.json.elements?.[0]?.totalShareStatistics?.likeCount || 0;
  const totalComments = sStat.json.elements?.[0]?.totalShareStatistics?.commentCount || 0;

  results.push({
    page_db_id: dbId,
    followers_count: totalFollowers,
    total_impressions: totalImpressions,
    total_shares: totalShares,
    total_likes: totalLikes,
    total_comments: totalComments
  });
}

return results;

