const results = [];
const postResponses = $('Fetch LinkedIn Posts').all();
const pages = $('Get Active LinkedIn Pages').all();

for (const resp of postResponses) {
  const elements = resp.json.elements || [];
  // Find which page this response belongs to by looking at the author URN in the first element
  const firstAuthor = elements[0]?.author;
  const matchedPage = pages.find(p => p.json.urn === firstAuthor) || { json: {} };
  const pageDbId = matchedPage.json.id;

  for (const element of elements) {
    const id = element.id;
    const author = element.author;
    // Extract commentary text/content
    const content = element.specificContent?.['com.linkedin.ugc.ShareContent']?.shareCommentary?.text || '';
    const publishedAtRaw = element.created?.time || Date.now();
    const publishedAt = new Date(publishedAtRaw).toISOString();

    // Construct standard LinkedIn share URL if organization page or member post
    // e.g. https://www.linkedin.com/feed/update/urn:li:share:123456
    const url = `https://www.linkedin.com/feed/update/${id}`;

    results.push({
      id,
      page_db_id: pageDbId,
      author_urn: author,
      content,
      url,
      published_at: publishedAt
    });
  }
}
return results;
